import{_ as e,o as t,c as s,ag as n}from"./chunks/framework.BDReElpY.js";const h=JSON.parse('{"title":"Automatic Differentiation (Autograd)","description":"","frontmatter":{},"headers":[],"relativePath":"archive/silicon/autograd.md","filePath":"archive/silicon/autograd.md"}'),i={name:"archive/silicon/autograd.md"};function o(r,a,l,p,c,d){return t(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="automatic-differentiation-autograd" tabindex="-1">Automatic Differentiation (Autograd) <a class="header-anchor" href="#automatic-differentiation-autograd" aria-label="Permalink to &quot;Automatic Differentiation (Autograd)&quot;">​</a></h1><p>Vex makes gradient computation a native feature of the language, enabling seamless Deep Learning and scientific computing workflows without external libraries.</p><h2 id="the-operator" tabindex="-1">The <code>@</code> Operator <a class="header-anchor" href="#the-operator" aria-label="Permalink to &quot;The \`@\` Operator&quot;">​</a></h2><p>Autograd is activated using the <code>@</code> block syntax or specific autograd intrinsics.</p><h3 id="block-syntax" tabindex="-1">Block Syntax <a class="header-anchor" href="#block-syntax" aria-label="Permalink to &quot;Block Syntax&quot;">​</a></h3><p>The <code>@{ ... }</code> block creates a differentiable scope. Inside this scope, operations on &quot;parameters&quot; are tracked to build a computation graph (or calculate gradients on the fly).</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn train_step(x: [f32], target: f32, w: [f32]): [f32] {</span></span>
<span class="line"><span>    let result = @{</span></span>
<span class="line"><span>        // 1. Mark &#39;w&#39; as a parameter to track</span></span>
<span class="line"><span>        let weights = $param(w);</span></span>
<span class="line"><span>        </span></span>
<span class="line"><span>        // 2. Perform tensor operations</span></span>
<span class="line"><span>        let pred = $sum(x * weights);</span></span>
<span class="line"><span>        </span></span>
<span class="line"><span>        // 3. Calculate loss</span></span>
<span class="line"><span>        let loss = (pred - target) ^ 2;</span></span>
<span class="line"><span>        </span></span>
<span class="line"><span>        // 4. Return the loss to be differentiated</span></span>
<span class="line"><span>        loss</span></span>
<span class="line"><span>    };</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // Extract results</span></span>
<span class="line"><span>    let loss_value = $val(result);</span></span>
<span class="line"><span>    let gradients = $grad(result); // Gradient of loss w.r.t weights</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    return gradients;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="intrinsics" tabindex="-1">Intrinsics <a class="header-anchor" href="#intrinsics" aria-label="Permalink to &quot;Intrinsics&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Intrinsic</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>$param(x)</code></td><td style="text-align:left;">Marks variable <code>x</code> as a leaf parameter for gradient tracking.</td></tr><tr><td style="text-align:left;"><code>$val(res)</code></td><td style="text-align:left;">Extracts the primal value (the result of the computation).</td></tr><tr><td style="text-align:left;"><code>$grad(res)</code></td><td style="text-align:left;">Extracts the gradient (the derivative w.r.t parameters).</td></tr><tr><td style="text-align:left;"><code>$detach(x)</code></td><td style="text-align:left;">Stops gradient propagation for a variable (useful for inference).</td></tr></tbody></table><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Vex implements <strong>Forward-Mode Automatic Differentiation</strong> (and plans for Reverse-Mode) using Dual Numbers or source-to-source transformation.</p><ol><li><strong>Dual Numbers:</strong> Each number is represented as $v + \\epsilon d$, where $\\epsilon^2 = 0$.</li><li><strong>Chain Rule:</strong> Operations automatically propagate derivaties: $$ \\frac{d}{dx}(f(g(x))) = f&#39;(g(x)) \\cdot g&#39;(x) $$</li><li><strong>Compiler Optimization:</strong> The Vex compiler (SIR) can fuse autograd operations with the computation loop, eliminating the memory overhead of storing the computation graph often seen in libraries like PyTorch.</li></ol><h2 id="supported-operations" tabindex="-1">Supported Operations <a class="header-anchor" href="#supported-operations" aria-label="Permalink to &quot;Supported Operations&quot;">​</a></h2><p>Most built-in math functions and operators are autograd-aware:</p><ul><li>Arithmetic: <code>+</code>, <code>-</code>, <code>*</code>, <code>/</code>, <code>^</code></li><li>Math Functions: <code>$sin</code>, <code>$cos</code>, <code>$exp</code>, <code>$log</code></li><li>Reductions: <code>$sum</code>, <code>$mean</code></li><li>Linear Algebra: <code>&lt;*&gt;</code>, <code>·</code></li></ul><h2 id="example-neural-network-layer" tabindex="-1">Example: Neural Network Layer <a class="header-anchor" href="#example-neural-network-layer" aria-label="Permalink to &quot;Example: Neural Network Layer&quot;">​</a></h2><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn linear_layer(input: [f32], weight: Matrix, bias: [f32]) -&gt; @Tensor {</span></span>
<span class="line"><span>    @{</span></span>
<span class="line"><span>        let w = $param(weight);</span></span>
<span class="line"><span>        let b = $param(bias);</span></span>
<span class="line"><span>        (input &lt;*&gt; w) + b</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div>`,17)])])}const g=e(i,[["render",o]]);export{h as __pageData,g as default};
